# View and modify OU filtering via the Entra Connect PowerShell module
Import-Module ADSync

# List all configured AD connectors
Get-ADSyncConnector | Select-Object Name, Type, Version

# Show current OU filtering configuration
$connector = Get-ADSyncConnector -Name 'contoso.com'
$connector.Partitions | ForEach-Object {
    Write-Output "Domain: $($_.Name)"
    $_.ContainerInclusionList | ForEach-Object { Write-Output "  Include: $_" }
    $_.ContainerExclusionList | ForEach-Object { Write-Output "  Exclude: $_" }
}

# Add an OU to the inclusion list (run Entra Connect wizard to apply)
# Note: OU filtering changes require re-running the installation wizard or
# using Set-ADSyncScheduler to trigger a full import after modifying filters

# Attribute-based scoping filter (sync only enabled users in HR OU)
# Done via Synchronization Rules Editor (GUI) or PowerShell:
$rule = Get-ADSyncRule | Where-Object { $_.Name -like '*In from AD - User*' -and $_.Direction -eq 'Inbound' } | Select-Object -First 1

# List existing scoping filters on the rule
$rule.ScopeFilter | ForEach-Object {
    $_.ScopeFilterGroup | ForEach-Object {
        "Attribute: $($_.Attribute), Operator: $($_.ComparisonOperator), Value: $($_.ComparisonValue)"
    }
}
